import { HomePageContainer } from "./styles"

export const HomePage = ({character, setCharacter}) => {

    const findCharacter = () => {
        axios.get("https://hp-api.onrender.com/api/characters")
        .then((response) => console.log(response.data[400].name))
        .catch((error) => {
          console.log(error)
        })
      }

      findCharacter()

    return (
        <HomePageContainer>
            <CharacterCard />
        </HomePageContainer>
    )
}
